mapper.sql:
WITH T_MSG AS ( SELECT A.MULAAPMSGHDKEY , B.MSGTYPE , B.DISPLAYMSG FROM TADMIN_MST_MULAAPMSG_HD A INNER JOIN TADMIN_MST_MULAAPMSG_DT B ON B.MULAAPMSGHDKEY = A.MULAAPMSGHDKEY
AND LAKEY = #{lakey}
AND A.CLOSDATE >= TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS')
)

mapper.select:
/* adm-menu-menu-sql-oracle.xml - selectMenuCount */
SELECT COUNT(1) FROM ( WITH RECURSIVE menu_tree_cnt AS ( SELECT ME.MEKEY, ME.MENM, ME.UPRMEKEY, ME.EQTYPE, ME.USEYN, ME.APKEY, ME.USKEY, ME.MEORDER, ARRAY[ME.MEORDER::TEXT, ME.MEKEY] AS sort_path, 1 AS depth FROM TADMIN_MST_ME ME WHERE ME.UPRMEKEY = '0' UNION ALL SELECT ME.MEKEY, ME.MENM, ME.UPRMEKEY, ME.EQTYPE, ME.USEYN, ME.APKEY, ME.USKEY, ME.MEORDER, p.sort_path || ME.MEORDER::TEXT || ME.MEKEY, p.depth + 1 FROM TADMIN_MST_ME ME INNER JOIN menu_tree_cnt p ON ME.UPRMEKEY = p.MEKEY ) SELECT * FROM menu_tree_cnt ) A INNER JOIN TADMIN_MST_URSCR B ON B.APKEY = A.APKEY AND B.USKEY = A.USKEY LEFT OUTER JOIN TADMIN_MST_ME C ON C.MEKEY = A.UPRMEKEY LEFT OUTER JOIN T_MSG D ON D.MULAAPMSGHDKEY = A.MENM AND D.MSGTYPE = 'MENU' LEFT OUTER JOIN T_MSG E ON E.MULAAPMSGHDKEY = C.MENM AND E.MSGTYPE = 'MENU'
ORDER BY A.sort_path

/* adm-menu-menu-sql-oracle.xml - selectMenuList */
SELECT '0' AS CHK , A.APKEY , A.MEKEY , A.MENM AS MENAME_TREE , A.MENM , D.DISPLAYMSG AS MELANG , A.depth - 1 AS MELVL , A.MEORDER , A.UPRMEKEY , C.MENM AS UPPERMENAME , E.DISPLAYMSG AS UPPERMELANG , A.USKEY , B.USNM , A.EQTYPE , A.DELYN , A.INSERTDATE , A.INSERTURKEY AS INSERTURNAME , A.UPDATEDATE , A.UPDATEURKEY AS UPDATEURNAME FROM ( WITH RECURSIVE menu_tree AS ( SELECT ME.MEKEY, ME.MENM, ME.UPRMEKEY, ME.EQTYPE, ME.USEYN, ME.APKEY, ME.USKEY, ME.MEORDER, ME.DELYN, ME.INSERTDATE, ME.INSERTURKEY, ME.UPDATEDATE, ME.UPDATEURKEY, ARRAY[ME.MEORDER::TEXT, ME.MEKEY] AS sort_path, 1 AS depth FROM TADMIN_MST_ME ME WHERE ME.UPRMEKEY = '0' UNION ALL SELECT ME.MEKEY, ME.MENM, ME.UPRMEKEY, ME.EQTYPE, ME.USEYN, ME.APKEY, ME.USKEY, ME.MEORDER, ME.DELYN, ME.INSERTDATE, ME.INSERTURKEY, ME.UPDATEDATE, ME.UPDATEURKEY, p.sort_path || ME.MEORDER::TEXT || ME.MEKEY, p.depth + 1 FROM TADMIN_MST_ME ME INNER JOIN menu_tree p ON ME.UPRMEKEY = p.MEKEY ) SELECT * FROM menu_tree ) A INNER JOIN TADMIN_MST_URSCR B ON B.APKEY = A.APKEY AND B.USKEY = A.USKEY LEFT OUTER JOIN TADMIN_MST_ME C ON C.MEKEY = A.UPRMEKEY LEFT OUTER JOIN T_MSG D ON D.MULAAPMSGHDKEY = A.MENM AND D.MSGTYPE = 'MENU' LEFT OUTER JOIN T_MSG E ON E.MULAAPMSGHDKEY = C.MENM AND E.MSGTYPE = 'MENU'
ORDER BY A.sort_path

/* adm-menu-menu-sql-oracle.xml - selectMenuDupCount */
SELECT
	COUNT(1)
FROM
	TADMIN_MST_ME


		AND MEKEY != #{mekey}

	AND DELYN = 'N'
	AND MEORDER = #{meorder}
	AND UPRMEKEY = #{uprmekey}
	AND EQTYPE = #{eqtype}

mapper.insert:
/* adm-menu-menu-sql-oracle.xml - insertMenu */
INSERT INTO TADMIN_MST_ME (
	  MEKEY
	, MENM
	, MEORDER
	, APKEY
	, USKEY
	, UPRMEKEY
	, EQTYPE
	, USEYN
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
) VALUES (
	  #{mekey}
	, #{menm}
	, #{meorder}
	, #{apkey}
	, #{uskey}
	, #{uprmekey}
	, #{eqtype}
	, #{useyn}
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
)

mapper.update:
/* adm-menu-menu-sql-oracle.xml - updateMenu */
UPDATE
    TADMIN_MST_ME
SET
	  MENM = #{menm}
	, MEORDER = #{meorder}
	, APKEY = #{apkey}
	, USKEY = #{uskey}
	, UPRMEKEY = #{uprmekey}
	, EQTYPE = #{eqtype}
	, DELYN	= #{delyn}
	, UPDATEDATE = #{sysdate}
	, UPDATEURKEY  = #{surkey}
WHERE
	MEKEY = #{mekey}
